SELECT AVG(temperature_degC) AS average_temperature
FROM paleo_data
WHERE reliable = 'Y';

SELECT temperature_degC
FROM paleo_data
WHERE reliable = 'Y' AND temperature_degC > 5;

SELECT core_id, core_length
FROM sediment_cores
WHERE core_length > 100;

SELECT core_id, core_length
FROM sediment_cores
ORDER BY core_length DESC;

SELECT *
FROM sediment_cores
WHERE core_length = (SELECT MAX(core_length) FROM sediment_cores);
